import{_ as a,o as i,c as e,ae as t}from"./chunks/framework.EHGTsUvI.js";const u=JSON.parse('{"title":"快速开始","description":"","frontmatter":{},"headers":[],"relativePath":"guide/quick-start.md","filePath":"guide/quick-start.md"}'),o={name:"guide/quick-start.md"};function r(h,l,n,d,s,c){return i(),e("div",null,[...l[0]||(l[0]=[t('<h1 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h1><p>本章节将帮助你快速上手 Apipseach 平台，从注册账号到使用 API 搜索功能。</p><h2 id="_1-注册账号" tabindex="-1">1. 注册账号 <a class="header-anchor" href="#_1-注册账号" aria-label="Permalink to &quot;1. 注册账号&quot;">​</a></h2><ol><li>打开浏览器访问 Apipseach 平台</li><li>点击右上角的「注册」按钮</li><li>填写邮箱、密码等信息</li><li>点击「注册」按钮完成注册</li></ol><h2 id="_2-登录平台" tabindex="-1">2. 登录平台 <a class="header-anchor" href="#_2-登录平台" aria-label="Permalink to &quot;2. 登录平台&quot;">​</a></h2><ol><li>打开浏览器访问 Apipseach 平台</li><li>点击右上角的「登录」按钮</li><li>输入邮箱和密码</li><li>点击「登录」按钮进入平台</li></ol><h2 id="_3-搜索-api" tabindex="-1">3. 搜索 API <a class="header-anchor" href="#_3-搜索-api" aria-label="Permalink to &quot;3. 搜索 API&quot;">​</a></h2><ol><li>在首页的搜索框中输入你需要的 API 关键词，例如「天气」</li><li>点击搜索按钮或按回车键</li><li>浏览搜索结果，查看 API 的详细信息</li></ol><h2 id="_4-查看-api-详情" tabindex="-1">4. 查看 API 详情 <a class="header-anchor" href="#_4-查看-api-详情" aria-label="Permalink to &quot;4. 查看 API 详情&quot;">​</a></h2><ol><li>在搜索结果中点击感兴趣的 API</li><li>查看 API 的详细文档，包括： <ul><li>API 描述</li><li>请求参数</li><li>响应格式</li><li>示例代码</li></ul></li></ol><h2 id="_5-生成代码" tabindex="-1">5. 生成代码 <a class="header-anchor" href="#_5-生成代码" aria-label="Permalink to &quot;5. 生成代码&quot;">​</a></h2><ol><li>在 API 详情页面，选择你需要的编程语言</li><li>点击「生成代码」按钮</li><li>复制生成的代码到你的项目中使用</li></ol><h2 id="_6-管理-api" tabindex="-1">6. 管理 API <a class="header-anchor" href="#_6-管理-api" aria-label="Permalink to &quot;6. 管理 API&quot;">​</a></h2><ol><li>点击左侧导航栏的「我的 API」</li><li>在这里你可以： <ul><li>收藏常用的 API</li><li>查看 API 的使用情况</li><li>设置 API 的监控规则</li></ul></li></ol><h2 id="_7-创建-api-文档" tabindex="-1">7. 创建 API 文档 <a class="header-anchor" href="#_7-创建-api-文档" aria-label="Permalink to &quot;7. 创建 API 文档&quot;">​</a></h2><ol><li>点击左侧导航栏的「创建 API」</li><li>填写 API 的基本信息</li><li>配置 API 的请求和响应格式</li><li>点击「保存」按钮完成创建</li></ol><h2 id="_8-查看监控数据" tabindex="-1">8. 查看监控数据 <a class="header-anchor" href="#_8-查看监控数据" aria-label="Permalink to &quot;8. 查看监控数据&quot;">​</a></h2><ol><li>点击左侧导航栏的「监控中心」</li><li>查看 API 的调用次数、响应时间等数据</li><li>设置告警规则，当 API 出现异常时及时通知</li></ol><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li>查看后续文档了解更多 API 详情</li><li>阅读相关文档了解如何配置平台</li></ul>',20)])])}const _=a(o,[["render",r]]);export{u as __pageData,_ as default};
